# This script merges multiple .tif chunks of SwissALTI3D elevation data into a
# single stitched master file.

import glob
import os
import rasterio
from rasterio.merge import merge

def stitch_swisstopo_chunks(input_folder, output_filepath):
    # 1. Gather all downloaded .tif files in the folder
    search_path = os.path.join(input_folder, "*.tif")
    tile_files = glob.glob(search_path)

    if not tile_files:
        print(f"No .tif files found in {input_folder}. Check your path.")
        return

    print(f"Found {len(tile_files)} chunks to stitch together...")

    # 2. Open all files as rasterio dataset objects
    src_files_to_mosaic = []
    for file in tile_files:
        src = rasterio.open(file)
        src_files_to_mosaic.append(src)

    print("Merging datasets geographically (this may take a moment)...")

    # 3. Merge the datasets
    # This automatically aligns overlapping borders and matches spatial references
    mosaic, out_trans = merge(src_files_to_mosaic)

    # 4. Copy the metadata from the first chunk to maintain CRS parameters
    meta = src_files_to_mosaic[0].meta.copy()

    # 5. Update the metadata to match the new merged dimensions and transform matrix
    meta.update({
        "driver": "GTiff",
        "height": mosaic.shape[1],
        "width": mosaic.shape[2],
        "transform": out_trans
    })

    # 6. Write the stitched mosaic file to disk
    print(f"Writing stitched master file to: {output_filepath}")
    with rasterio.open(output_filepath, "w", **meta) as dest:
        dest.write(mosaic)

    # 7. Explicitly close all open dataset files to free up memory
    for src in src_files_to_mosaic:
        src.close()

    print("Stitching process completed successfully!")

